def fetch_remote_dependencies(url):
    try:
        with urllib.request.urlopen(url) as response:
            data = response.read()
            config = json.loads(data.decode('utf-8'))
            return config.get('dependencies', []), config.get('additional_packages', [])
    except Exception as e:
        print(f"Warning: Could not fetch remote dependencies: {e}")
        return [], []


